svg.script:
// TKL Keyboard Layout - 87 keys
// Based on schematic reference
// Unit size for keys
const U = 5; // 1 unit = 5px
const keyH = 5; // key height
const gap = 0.5; // gap between keys

// Keyboard positioning
const kbX = 44; // keyboard start X
const kbY = 62; // keyboard start Y (function row)

// Key map: each key has {id, row, x, w} where w is width in units
const keyMap = {
  // Row 1: Function row (y = kbY)
  'ESC':    { row: 0, x: 0, w: 1 },
  'F1':     { row: 0, x: 1.5, w: 1 },
  'F2':     { row: 0, x: 2.5, w: 1 },
  'F3':     { row: 0, x: 3.5, w: 1 },
  'F4':     { row: 0, x: 4.5, w: 1 },
  'F5':     { row: 0, x: 5.75, w: 1 },
  'F6':     { row: 0, x: 6.75, w: 1 },
  'F7':     { row: 0, x: 7.75, w: 1 },
  'F8':     { row: 0, x: 8.75, w: 1 },
  'F9':     { row: 0, x: 10, w: 1 },
  'F10':    { row: 0, x: 11, w: 1 },
  'F11':    { row: 0, x: 12, w: 1 },
  'F12':    { row: 0, x: 13, w: 1 },
  'PRTSC':  { row: 0, x: 14.25, w: 1 },
  'SCRLK':  { row: 0, x: 15.25, w: 1 },
  'PAUSE':  { row: 0, x: 16.25, w: 1 },

  // Row 2: Number row (y = kbY + 6)
  'GRAVE':  { row: 1, x: 0, w: 1 },
  '1':      { row: 1, x: 1, w: 1 },
  '2':      { row: 1, x: 2, w: 1 },
  '3':      { row: 1, x: 3, w: 1 },
  '4':      { row: 1, x: 4, w: 1 },
  '5':      { row: 1, x: 5, w: 1 },
  '6':      { row: 1, x: 6, w: 1 },
  '7':      { row: 1, x: 7, w: 1 },
  '8':      { row: 1, x: 8, w: 1 },
  '9':      { row: 1, x: 9, w: 1 },
  '0':      { row: 1, x: 10, w: 1 },
  'MINUS':  { row: 1, x: 11, w: 1 },
  'EQUAL':  { row: 1, x: 12, w: 1 },
  'BKSP':   { row: 1, x: 13, w: 1.5 },
  'INS':    { row: 1, x: 14.75, w: 1 },
  'HOME':   { row: 1, x: 15.75, w: 1 },
  'PGUP':   { row: 1, x: 16.75, w: 1 },

  // Row 3: QWERTY row (y = kbY + 12)
  'TAB':    { row: 2, x: 0, w: 1.25 },
  'Q':      { row: 2, x: 1.25, w: 1 },
  'W':      { row: 2, x: 2.25, w: 1 },
  'E':      { row: 2, x: 3.25, w: 1 },
  'R':      { row: 2, x: 4.25, w: 1 },
  'T':      { row: 2, x: 5.25, w: 1 },
  'Y':      { row: 2, x: 6.25, w: 1 },
  'U':      { row: 2, x: 7.25, w: 1 },
  'I':      { row: 2, x: 8.25, w: 1 },
  'O':      { row: 2, x: 9.25, w: 1 },
  'P':      { row: 2, x: 10.25, w: 1 },
  'LBRACK': { row: 2, x: 11.25, w: 1 },
  'RBRACK': { row: 2, x: 12.25, w: 1 },
  'BSLASH': { row: 2, x: 13.25, w: 1.25 },
  'DEL':    { row: 2, x: 14.75, w: 1 },
  'END':    { row: 2, x: 15.75, w: 1 },
  'PGDN':   { row: 2, x: 16.75, w: 1 },

  // Row 4: ASDF row (y = kbY + 18)
  'CAPS':   { row: 3, x: 0, w: 1.5 },
  'A':      { row: 3, x: 1.5, w: 1 },
  'S':      { row: 3, x: 2.5, w: 1 },
  'D':      { row: 3, x: 3.5, w: 1 },
  'F':      { row: 3, x: 4.5, w: 1 },
  'G':      { row: 3, x: 5.5, w: 1 },
  'H':      { row: 3, x: 6.5, w: 1 },
  'J':      { row: 3, x: 7.5, w: 1 },
  'K':      { row: 3, x: 8.5, w: 1 },
  'L':      { row: 3, x: 9.5, w: 1 },
  'SEMI':   { row: 3, x: 10.5, w: 1 },
  'QUOTE':  { row: 3, x: 11.5, w: 1 },
  'ENTER':  { row: 3, x: 12.5, w: 2 },
  // No nav keys on this row

  // Row 5: ZXCV row (y = kbY + 24)
  'LSHIFT': { row: 4, x: 0, w: 2 },
  'Z':      { row: 4, x: 2, w: 1 },
  'X':      { row: 4, x: 3, w: 1 },
  'C':      { row: 4, x: 4, w: 1 },
  'V':      { row: 4, x: 5, w: 1 },
  'B':      { row: 4, x: 6, w: 1 },
  'N':      { row: 4, x: 7, w: 1 },
  'M':      { row: 4, x: 8, w: 1 },
  'COMMA':  { row: 4, x: 9, w: 1 },
  'PERIOD': { row: 4, x: 10, w: 1 },
  'SLASH':  { row: 4, x: 11, w: 1 },
  'RSHIFT': { row: 4, x: 12, w: 2.5 },
  'UP':     { row: 4, x: 15.75, w: 1 }, // Up arrow alone

  // Row 6: Bottom row (y = kbY + 30)
  'LCTRL':  { row: 5, x: 0, w: 1.25 },
  'LWIN':   { row: 5, x: 1.25, w: 1 },
  'LALT':   { row: 5, x: 2.25, w: 1.25 },
  'SPACE':  { row: 5, x: 3.5, w: 5.5 },
  'RALT':   { row: 5, x: 9, w: 1.25 },
  'RWIN':   { row: 5, x: 10.25, w: 1 },
  'MENU':   { row: 5, x: 11.25, w: 1 },
  'RCTRL':  { row: 5, x: 12.25, w: 1.25 },
  'LEFT':   { row: 5, x: 14.75, w: 1 },
  'DOWN':   { row: 5, x: 15.75, w: 1 },
  'RIGHT':  { row: 5, x: 16.75, w: 1 }
};

// Count keys
const keyCount = Object.keys(keyMap).length;
console.log('Total keys:', keyCount); // Should be 87

// Scale factor to fit keyboard in available space
// Available width: ~112px (from x=44 to x=156)
// Keyboard width in units: ~17.75 units
// Scale: 112 / (17.75 * 5) = ~1.26, but let's use a cleaner scale
const scale = 1.25; // Scale to fill keyboard width

// Generate key rectangles
const keysGroup = document.getElementById('keys');
const allKeyPositions = [];

Object.entries(keyMap).forEach(([id, key]) => {
  const x = kbX + key.x * U * scale;
  const y = kbY + key.row * 6;
  const w = key.w * U * scale - gap;
  const h = keyH;

  const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
  rect.setAttribute('class', 'key-cap');
  rect.setAttribute('x', x);
  rect.setAttribute('y', y);
  rect.setAttribute('width', w);
  rect.setAttribute('height', h);
  rect.setAttribute('rx', '0.5');
  rect.setAttribute('data-key', id);
  keysGroup.appendChild(rect);

  // Store center position for animation
  allKeyPositions.push({
    id: id,
    x: x + w / 2,
    y: y + h / 2
  });
});

class PerlinNoise {
  constructor(seed = Math.random() * 10000) {
    this.p = [];
    for (let i = 0; i < 256; i++) this.p[i] = i;
    let n = seed;
    for (let i = 255; i > 0; i--) {
      n = (n * 16807) % 2147483647;
      const j = n % (i + 1);
      [this.p[i], this.p[j]] = [this.p[j], this.p[i]];
    }
    this.p = this.p.concat(this.p);
  }
  fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  lerp(a, b, t) { return a + t * (b - a); }
  grad(hash, x) { return (hash & 1) === 0 ? x : -x; }
  noise1D(x) {
    const xi = Math.floor(x) & 255;
    const xf = x - Math.floor(x);
    const u = this.fade(xf);
    return this.lerp(this.grad(this.p[xi], xf), this.grad(this.p[xi + 1], xf - 1), u);
  }
}

// Keys grouped by region for each tentacle (adjusted for scale 1.25)
// Keyboard spans x=44 to x=155
const keyRegions = [
  allKeyPositions.filter(k => k.x < 75),      // left side
  allKeyPositions.filter(k => k.x >= 65 && k.x < 105),  // left-center
  allKeyPositions.filter(k => k.x >= 95 && k.x < 135),  // right-center
  allKeyPositions.filter(k => k.x >= 125)     // right side
];

// Tap animation curve
function tapCurve(progress) {
  if (progress < 0.12) {
    const t = progress / 0.12;
    return { reach: -0.15 * Math.sin(t * Math.PI), curl: -0.3 * t };
  } else if (progress < 0.35) {
    const t = (progress - 0.12) / 0.23;
    const ease = t * t;
    return { reach: ease, curl: 0.4 * ease };
  } else if (progress < 0.5) {
    const t = (progress - 0.35) / 0.15;
    return { reach: 1.0, curl: 0.4 - 0.1 * Math.sin(t * Math.PI) };
  } else {
    const t = (progress - 0.5) / 0.5;
    const ease = 1 - (1 - t) * (1 - t);
    return { reach: 1 - ease, curl: 0.3 * (1 - ease) };
  }
}

function lerp(a, b, t) {
  return a + (b - a) * t;
}

const clauditoX = 100;
const clauditoY = 18;

const tentacles = [
  {
    el: document.getElementById('leg0'),
    anchorX: clauditoX - 18,
    anchorY: clauditoY + 34,
    hoverX: 60,
    hoverY: 58,
    keys: keyRegions[0],
    noise: {
      curl1: new PerlinNoise(1),
      curl2: new PerlinNoise(11),
      sway: new PerlinNoise(21),
      hover: new PerlinNoise(31),
      keySelect: new PerlinNoise(41)
    },
    phase: 0,
    tapping: false,
    tapProgress: 0,
    tapDuration: 0.45,
    lastTapTime: 0,
    nextTapDelay: 0.08,
    targetKey: null,
    preTapX: 0,
    preTapY: 0
  },
  {
    el: document.getElementById('leg1'),
    anchorX: clauditoX - 10,
    anchorY: clauditoY + 34,
    hoverX: 85,
    hoverY: 58,
    keys: keyRegions[1],
    noise: {
      curl1: new PerlinNoise(2),
      curl2: new PerlinNoise(12),
      sway: new PerlinNoise(22),
      hover: new PerlinNoise(32),
      keySelect: new PerlinNoise(42)
    },
    phase: 1.3,
    tapping: false,
    tapProgress: 0,
    tapDuration: 0.40,
    lastTapTime: 0.12,
    nextTapDelay: 0.06,
    targetKey: null,
    preTapX: 0,
    preTapY: 0
  },
  {
    el: document.getElementById('leg2'),
    anchorX: clauditoX + 10,
    anchorY: clauditoY + 34,
    hoverX: 115,
    hoverY: 58,
    keys: keyRegions[2],
    noise: {
      curl1: new PerlinNoise(3),
      curl2: new PerlinNoise(13),
      sway: new PerlinNoise(23),
      hover: new PerlinNoise(33),
      keySelect: new PerlinNoise(43)
    },
    phase: 2.7,
    tapping: false,
    tapProgress: 0,
    tapDuration: 0.42,
    lastTapTime: 0.18,
    nextTapDelay: 0.07,
    targetKey: null,
    preTapX: 0,
    preTapY: 0
  },
  {
    el: document.getElementById('leg3'),
    anchorX: clauditoX + 18,
    anchorY: clauditoY + 34,
    hoverX: 140,
    hoverY: 58,
    keys: keyRegions[3],
    noise: {
      curl1: new PerlinNoise(4),
      curl2: new PerlinNoise(14),
      sway: new PerlinNoise(24),
      hover: new PerlinNoise(34),
      keySelect: new PerlinNoise(44)
    },
    phase: 4.1,
    tapping: false,
    tapProgress: 0,
    tapDuration: 0.44,
    lastTapTime: 0.25,
    nextTapDelay: 0.09,
    targetKey: null,
    preTapX: 0,
    preTapY: 0
  }
];

let time = 0;
let lastTime = performance.now();

function animate(currentTime) {
  // Skip animation when paused (set by parent page's IntersectionObserver)
  if (window.isPaused) {
    lastTime = currentTime;
    requestAnimationFrame(animate);
    return;
  }
  const deltaTime = (currentTime - lastTime) / 1000;
  lastTime = currentTime;
  time += deltaTime;

  tentacles.forEach(t => {
    const p = t.phase;
    const n = t.noise;

    const hoverOffsetX = n.hover.noise1D(time * 0.4 + p) * 15;
    const hoverOffsetY = n.hover.noise1D(time * 0.5 + p + 100) * 8;

    if (!t.tapping) {
      if (time - t.lastTapTime > t.nextTapDelay) {
        const keyNoise = n.keySelect.noise1D(time * 2 + p);
        const keyIndex = Math.floor((keyNoise * 0.5 + 0.5) * t.keys.length);
        t.targetKey = t.keys[Math.min(keyIndex, t.keys.length - 1)];

        t.preTapX = t.hoverX + hoverOffsetX;
        t.preTapY = t.hoverY + hoverOffsetY;

        t.tapping = true;
        t.tapProgress = 0;
        const pauseChance = n.keySelect.noise1D(time * 0.3 + p + 50);
        if (pauseChance > 0.7) {
          t.nextTapDelay = 0.4 + (pauseChance - 0.7) * 2.0;
        } else {
          t.nextTapDelay = 0.02 + Math.random() * 0.08;
        }
      }
    } else {
      t.tapProgress += deltaTime / t.tapDuration;
      if (t.tapProgress >= 1) {
        t.tapping = false;
        t.tapProgress = 0;
        t.lastTapTime = time;
      }
    }

    let tipX, tipY;

    if (t.tapping && t.targetKey) {
      const tap = tapCurve(t.tapProgress);
      tipX = lerp(t.preTapX, t.targetKey.x, tap.reach);
      tipY = lerp(t.preTapY, t.targetKey.y, tap.reach);
      if (tap.reach < 0) {
        tipY += tap.reach * 10;
      }
    } else {
      tipX = t.hoverX + hoverOffsetX;
      tipY = t.hoverY + hoverOffsetY;
    }

    const dx = tipX - t.anchorX;
    const dy = tipY - t.anchorY;
    const dist = Math.sqrt(dx * dx + dy * dy);

    const perpX = -dy / dist;
    const perpY = dx / dist;

    const tapCurl = t.tapping ? tapCurve(t.tapProgress).curl : 0;

    const baseCurl1 = n.curl1.noise1D(time * 1.0 + p) * 16;
    const baseCurl2 = n.curl2.noise1D(time * 1.3 + p + 10) * 20;

    const curl1 = baseCurl1 * (1 + tapCurl);
    const curl2 = baseCurl2 * (1 + tapCurl * 0.6);

    const sway1 = n.sway.noise1D(time * 0.5 + p) * 5;
    const sway2 = n.sway.noise1D(time * 0.7 + p + 5) * 7;

    const cp1x = t.anchorX + dx * 0.33 + perpX * curl1 + sway1;
    const cp1y = t.anchorY + dy * 0.33 + perpY * curl1;

    const cp2x = t.anchorX + dx * 0.66 + perpX * curl2 + sway2;
    const cp2y = t.anchorY + dy * 0.66 + perpY * curl2;

    const path = `M ${t.anchorX} ${t.anchorY} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${tipX} ${tipY}`;
    t.el.setAttribute('d', path);
  });

  requestAnimationFrame(animate);
}

requestAnimationFrame(animate);
